class Solution:
    def validateProjection(self, projection: dict) -> bool:
        def is_object(obj) -> bool:
            return isinstance(obj, dict)

        def has_key(obj, key) -> bool:
            return key in obj

        def validate(obj) -> bool:
            for key in obj:
                if is_object(obj[key]):
                    if not has_key(obj[key], '$'):
                        if not self.validateProjection(obj[key]):
                            return False
                    else:
                        if not self.validateProjection(obj[key]):
                            return False
            return True

        return validate(projection)
